#include <bits/stdc++.h>
using namespace std;

bool judge(int x, int p) {
    int s = 0;
    while (x) {
        s += x % 10;
        x /= 10;
    }
    // cout << s << endl;
    return (s % p);
}

int main() {
    int n, p, x;
    cin >> n >> p;
    x = pow(10, (n - 1));
    if (n * 9 < p) {
        cout << x;
        return 0;
    }
    while (judge(x, p)) x++;
    cout << x;
    return 0;
}
